INSERT INTO `quiz_options` (`id`, `question_id`, `option_text`, `option_desc`, `icon_name`, `metadata`, `created_at`, `option_text_bn`, `option_desc_bn`, `is_active`) VALUES
(1, 1, 'Weekend Explorer', 'Long journeys discovering new horizons.', '', '{}', '2026-05-06 01:38:43', 'উইকেন্ড এক্সপ্লোরার', 'দীর্ঘ ভ্রমণে নতুন দিগন্তের সন্ধান।', 1),
(2, 1, 'Daily Commuter', 'Navigating the city with efficiency and style.', '', '{}', '2026-05-06 01:38:43', 'ডেইলি কমিউটার', 'দক্ষতা ও স্টাইলের সাথে শহরের পথে চলাচল।', 1),
(4, 4, 'Roaming the City', 'A stylish Eid-night cruise through glowing city streets filled with festive energy and modern vibes.', '', '{\"personality\":\"The Festive Explorer: Loves vibrant nightlife, premium urban aesthetics, and memorable Eid adventures with friends.\",\"scene\":\"An ultra-posh international city street inspired by Singapore or New York luxury districts during a premium Eid holiday. The background features clean wide roads, premium modern architecture, sleek glass towers, luxury fashion storefronts, polished pavements, and an elegant warm Eid festive glow. Only one person is visible.\"}', '2026-05-06 01:38:43', 'রোমিং দ্য সিটি', 'ঝলমলে শহরের রাস্তায় স্টাইলিশ ঈদ রাতের ভ্রমণ।', 0),
(5, 4, 'Hangout at Cafe', 'A warm and elegant Eid cafe meetup filled with comfort, laughter, and premium social vibes.', '', '{\"personality\":\"The Social Minimalist: Enjoys meaningful conversations, aesthetic spaces, and relaxed festive moments with close friends.\",\"scene\":\"A luxurious international-style café exterior inspired by New York or Singapore during a premium Eid holiday evening. The background features a sophisticated glass façade, warm designer accent lighting, premium marble textures, stylish outdoor lounge seating, elegant upscale outdoor ambience, and luxury signage with no readable brand names. Only one person is visible. \"}', '2026-05-06 01:38:43', 'ক্যাফেতে আড্ডা', 'বন্ধুদের সাথে উষ্ণ ও প্রাণবন্ত ঈদ ক্যাফে মুহূর্ত।', 0),
(7, 3, 'Freedom Rider', 'For riders who chase open roads, new routes, and limitless possibilities.', '', '{\"color\":\"Blue\"}', '2026-05-06 01:38:43', 'ফ্রিডম রাইডার', 'খোলা রাস্তা, নতুন পথ এবং সীমাহীন সম্ভাবনার খোঁজে থাকা রাইডারদের জন্য।', 1),
(8, 3, 'Energy Rider', 'For bold riders who bring passion, speed, and confidence to every journey.', 'red', '{\"color\":\"Red\"}', '2026-05-06 01:38:43', 'এনার্জি রাইডার', 'সাহসী রাইডারদের জন্য, যারা প্রতিটি যাত্রায় আবেগ, গতি এবং আত্মবিশ্বাস নিয়ে আসে।', 1),
(9, 3, 'Smart Rider', 'For riders who stay calm, think sharp, and choose the right path with control.', '', '{\"color\":\"Green\"}', '2026-05-06 01:38:43', 'স্মার্ট রাইডার', 'শান্ত, তীক্ষ্ণ চিন্তাশীল এবং নিয়ন্ত্রণের সাথে সঠিক পথ বেছে নেওয়া রাইডারদের জন্য।', 1),
(11, 1, 'Speed Enthusiast', 'Fast roads, quick pickup, and sporty control for riders who love speed.', '', '{}', '2026-05-07 16:23:11', 'স্পিড এনথুসিয়াস্ট', 'রোমাঞ্চকর পারফরম্যান্স এবং উচ্চ গতির নিয়ন্ত্রণের অভিজ্ঞতা।', 1),
(12, 1, 'City Racer', 'City traffic, short rides, and stylish daily movement with smooth handling.', '', '{}', '2026-05-07 16:23:32', 'সিটি রেসার', 'শহরের ব্যস্ত রাস্তায় স্টাইলিশ ও স্মার্ট চলাচলের সঙ্গী।', 1),
(13, 1, 'Mountain Trekker', 'Hill roads, long climbs, and rough turns with strong balance and power.', '', '{}', '2026-05-07 16:23:57', 'মাউন্টেন ট্রেকার', 'পাহাড়ি রাস্তা ও অ্যাডভেঞ্চারপ্রিয় দীর্ঘ ভ্রমণের উপযুক্ত সঙ্গী।', 1),
(14, 1, 'Off Road Ruler', 'Dusty roads, village tracks, and broken paths with confident riding.', '', '{}', '2026-05-07 16:24:19', 'অফ রোড রুলার', 'দুর্গম রাস্তা ও অফ-রোড অভিযানে শক্তিশালী পারফরম্যান্সের প্রতীক।', 1),
(15, 1, 'Beach Rider', 'Coastal roads, relaxed cruising, and sunset rides with comfort and style.', '', '{}', '2026-05-07 16:24:41', 'বিচ রাইডার', 'সমুদ্রতীরবর্তী আরামদায়ক ভ্রমণ ও মুক্তির অনুভূতির জন্য উপযুক্ত।', 1),
(16, 4, 'Day Trip at Resort', 'A refreshing Eid escape into luxury, sunshine, and peaceful resort relaxation.', '', '{\"personality\":\"The Luxury Escapist: Seeks calm experiences, scenic beauty, and premium holiday moments away from the city.\",\"scene\":\"A luxurious Maldives-inspired resort pathway during a premium Eid day-trip. The background features clean lush tropical greenery, a white stone pathway, premium beach villas, hints of bright turquoise water, palm trees gently swaying, soft cinematic sunlight, and a calm luxury holiday atmosphere. Only one person is visible.\"}', '2026-05-08 17:40:32', 'রিসোর্টে একদিনের ভ্রমণ', 'ঈদের ছুটিতে বিলাসিতা, রোদেলা আবহ আর শান্তিময় রিসোর্টে আরামের এক সতেজ অভিজ্ঞতা।', 0),
(17, 4, 'Chill with Friends', 'A joyful Eid gathering filled with laughter, bonding, and unforgettable chill moments.', '', '{\"personality\":\"The Friendly Soul: Values connection, celebration, and relaxed quality time with friends during festive moments.\",\"scene\":\"A premium Eid holiday outdoor garden setting directly outside a luxury ground-floor lounge, with a towering Singapore or New York style city skyline in the far background. Only one person is visible. The setting features a manicured green lawn, clean stone pavers, and lush tropical greenery wrapped in warm glowing fairy lights. A marble mocktail table with elegant glassware and a traditional decorative Eid lantern are placed nearby. \"}', '2026-05-08 17:42:31', 'বন্ধুদের সঙ্গে আড্ডা', 'হাসি, বন্ধুত্ব আর স্মরণীয় আড্ডায় ভরা আনন্দময় এক ঈদের মিলনমেলা।', 0),
(19, 3, 'Precision Rider', 'For focused riders who value discipline, control, and timeless road presence.', 'black', '{\"color\":\"Black\"}', '2026-05-09 19:12:03', 'প্রিসিশন রাইডার', 'মনোযোগী রাইডারদের জন্য, যারা শৃঙ্খলা, নিয়ন্ত্রণ এবং চিরন্তন রোড প্রেজেন্সকে মূল্য দেয়।', 1),
(20, 3, 'All-Round Rider', 'For riders who blend confidence, balance, style, and spirit into one complete persona.', '', '{\"color\":\"White\"}', '2026-05-09 19:13:20', 'অল-রাউন্ড রাইডার', 'যারা আত্মবিশ্বাস, ভারসাম্য, স্টাইল এবং স্পিরিটকে এক সম্পূর্ণ ব্যক্তিত্বে মিলিয়ে নেয়।', 1),
(21, 2, 'City Life', 'A high-speed, sophisticated journey through the heart of a vibrant night-time metropolis.', '', '{\"personality\":\"The Modern Urbanite: Driven by sophistication, nightlife energy, and a premium metropolitan identity.\",\"scene\":\"A cinematic modern city night road with a long, clean asphalt street stretching into the distance. Tall glass skyscrapers, glowing LED billboards, and premium shopfronts line both sides. Inspired by a blend of NYC and Singapore. Bright urban streetlights with realistic reflections on the road surface. High-detail realistic environment, premium automotive photography style, cinematic depth.\"}', '2026-05-06 01:38:43', 'সিটি লাইফ', 'আলোকোজ্জ্বল মহানগরের প্রাণবন্ত রাতের রাস্তায় গতিময় যাত্রা।', 1),
(22, 2, 'Beaches', 'A peaceful coastal ride beside crystal-clear blue waters, soft white sands, and luxury tropical villas.', '', '{\"personality\":\"The Serene Traveler: Motivated by freedom, calmness, and the relaxation of scenic coastal experiences.\",\"scene\":\"A serene coastal marine drive road beside a tropical Maldives-style beach. Crystal-clear blue ocean, white sand, palm trees, and luxury beach villas in the background. Soft sunlight with a calm sea breeze mood. Open scenic road, realistic premium travel photography, cinematic composition, peaceful and aspirational atmosphere.\"}', '2026-05-06 01:38:43', 'বিচেস', 'নীল সমুদ্র, সাদা বালুকাবেলা এবং শান্ত উপকূলীয় ভ্রমণের অনুভূতি।', 1),
(23, 2, 'Hills', 'A peaceful, winding journey through lush green mountains, fresh air, and golden-hour mist.', '', '{\"personality\":\"The Nature Enthusiast: Values peace, elevation, and the refreshing spirit of scenic mountain adventures.\",\"scene\":\"A cinematic winding hill road through lush green mountains, layered hills in the background, soft morning mist, pine trees, golden-hour sunlight, clear open road, fresh mountain atmosphere, realistic scenic travel photography, premium cinematic depth, peaceful adventurous riding mood.\"}', '2026-05-08 17:40:32', 'হিলস', 'সবুজ পাহাড়, নির্মল বাতাস এবং শান্ত প্রকৃতির পথে ভ্রমণ।', 1),
(24, 2, 'Off-Roads', 'A raw and challenging adventure across uneven dirt roads, rocky terrains, and dust-filled trails.', '', '{\"personality\":\"The Adventurous Trailblazer: Defined by toughness, exploration, and a passion for raw riding energy.\",\"scene\":\"A cinematic off-road racing trail, uneven dirt road, rocky terrain, dust particles, rugged hills and mountains in the background, dramatic wide sky, adventurous riding atmosphere, premium realistic outdoor photography, powerful off-road mood, high-detail terrain, cinematic action-ready composition.\"}', '2026-05-08 17:42:31', 'অফ-রোডস', 'কাঁচা রাস্তা, পাথুরে পথ এবং চ্যালেঞ্জিং অফ-রোড অভিযানের অভিজ্ঞতা।', 1);

